public void testBugCollections447_RemoveAfterNext() {
    final List<String> treeList = new TreeList<String>();
    treeList.add("A");
    treeList.add("B");
    treeList.add("C");
    treeList.add("D");

    final ListIterator<String> li = treeList.listIterator();
    assertEquals("A", li.next());
    assertEquals("B", li.next());

    li.remove(); // Deletes "B"

    // next() after remove() should return the element after the one just removed
    assertEquals("C", li.next());
}

public void testBugCollections447_RemoveAtStart() {
    final List<String> treeList = new TreeList<String>();
    treeList.add("A");
    treeList.add("B");
    treeList.add("C");

    final ListIterator<String> li = treeList.listIterator();
    assertEquals("A", li.next());
    assertEquals("B", li.next());
    assertEquals("A", li.previous());

    li.remove(); // Deletes "A"

    // next() after remove() should return "B"
    assertEquals("B", li.next());
}

public void testBugCollections447_RemoveAtEnd() {
    final List<String> treeList = new TreeList<String>();
    treeList.add("A");
